            //
            aOrbiterD = ((aOrbiterD + aOrbiterA) + 0x5AC95540593B570CULL) + aPhaseFOrbiterUpdateSaltB[((aIndex + 9U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterD) ^ 0x7B73D687704083A6ULL;
