            //
            aOrbiterD = (aOrbiterD + aOrbiterI) + 0x1587F51521B184E7ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 0x2A56F66DEA73DF15ULL;
            aOrbiterC = RotL64((aOrbiterC * 0xD488C674543B9301ULL), 5U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterH) + 0x2E94EA26F59DCB6BULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterC) ^ 0xFEAD39CC6FAF7A38ULL;
            aOrbiterA = RotL64((aOrbiterA * 0xCF053202E9021DB5ULL), 51U);
