            aCross = (RotL64(aWorkLaneC[((S_BLOCK1 - aIndex + 3980U)) & S_BLOCK1], 18U) ^ RotL64(aWorkLaneD[((S_BLOCK1 - aIndex + 3169U)) & S_BLOCK1], 3U));
            aCross ^= RotL64(aInvestLaneA[((S_BLOCK1 - aIndex + 2071U)) & S_BLOCK1], 47U);
            aCross = TwistMix64::DiffuseC(aCross);
            //
            aScatter = (RotL64(aIngress, 56U) ^ RotL64(aCross, 29U)) ^ (RotL64(aPrevious, 5U) + RotL64(aCarry, 41U));
            aScatter = TwistMix64::DiffuseB(aScatter);
            //
            aOrbiterE = (aWandererG + RotL64(aScatter, 23U)) + 0xD53CB194D41D6C69ULL;
            aOrbiterF = (aWandererK + RotL64(aIngress, 47U)) + 0x88E4C5E89AAA4D7DULL;
            aOrbiterH = ((aWandererC + RotL64(aCross, 27U)) + 0x6F9568C5BE723FA3ULL) + aPhaseGOrbiterAssignSaltB[(((31U - aIndex) + 3U)) & S_SALT1];
            aOrbiterG = ((aWandererB + RotL64(aPrevious, 56U)) + RotL64(aCarry, 5U)) + 0xA4512A19CD06EB34ULL;
            aOrbiterI = (aWandererF + RotL64(aCross, 35U)) + 0x69FC1A164277A4DEULL;
            aOrbiterB = ((aWandererD + RotL64(aScatter, 3U)) + RotL64(aCarry, 21U)) + 0xB0558E2E99A7DA73ULL;
            aOrbiterK = ((aWandererE + RotL64(aIngress, 11U)) + 0xA435B04C316526D7ULL) + aPhaseGOrbiterAssignSaltE[(((31U - aIndex) + 23U)) & S_SALT1];
            aOrbiterC = (aWandererA + RotL64(aPrevious, 53U)) + 0x5B4D21CCE5427BDBULL;
            aOrbiterJ = (aWandererH + RotL64(aIngress, 13U)) + 0x146496AB7D554119ULL;
            aOrbiterD = ((aWandererJ + RotL64(aCross, 19U)) + RotL64(aCarry, 57U)) + 0x4BA76BC551FD89DEULL;
            aOrbiterA = (aWandererI + RotL64(aScatter, 50U)) + 0x22C225E60B69959CULL;
            //
            aOrbiterE = (aOrbiterE + aOrbiterF) + 0x0571C580AD42BC31ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterE) ^ 0xA1BB7ED6E27475B3ULL;
            aOrbiterH = RotL64((aOrbiterH * 0xDDE41539F99B0E0FULL), 5U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterH) + 0x1A4184BDAAE9F4E2ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterG) ^ 0xC48FE022D835B933ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x89D939EDAA28C71DULL), 35U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterB) + 0x6C1A3CCD424EA1B1ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterF) ^ 0x4614708568D99236ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x78F5F06165E5EF9FULL), 27U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterG) + 0x2BEFC3F295EA8C14ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterB) ^ 0xC4B9B0C196D16A7EULL;
            aOrbiterC = RotL64((aOrbiterC * 0x7010A8DFC6E58223ULL), 11U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterK) + 0x0F63B645C9DB4422ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterH) ^ 0xDE05929A44BDC58FULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x0843509340E4935DULL), 53U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterI) + 0xA8933A039AE5C16DULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterC) ^ 0x329E22DE1C25BE03ULL;
            aOrbiterD = RotL64((aOrbiterD * 0x3982F63223F25405ULL), 39U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterA) + 0x6CBCEC548F0BAFC6ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 0x30373DD7368CA1FAULL;
            aOrbiterF = RotL64((aOrbiterF * 0x35851591B5775B87ULL), 43U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterD) + 0x16F246602CDF8CD7ULL) + aPhaseGOrbiterUpdateSaltF[(((31U - aIndex) + 13U)) & S_SALT1];
            aOrbiterB = (aOrbiterB ^ aOrbiterA) ^ 0x1CD1E2C26047EE9EULL;
            aOrbiterB = RotL64((aOrbiterB * 0x9567350921F04C6DULL), 41U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterC) + 0x90B94653D07BD553ULL) + aPhaseGOrbiterUpdateSaltB[((aIndex + 20U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterK) ^ 0x4291943E879EAA93ULL;
            aOrbiterA = RotL64((aOrbiterA * 0x585E25AC56485DCDULL), 23U);
